import{_ as l,c as i,o as t,a5 as e,j as a}from"./chunks/framework.Dtwt352Q.js";const _=JSON.parse('{"title":"v1.1.17：桌面应用集成与 Homebrew 升级修复","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.17.md","filePath":"changelog/v1.1.17.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.17.md"};function d(h,r,n,s,c,b){return t(),i("div",null,[...r[0]||(r[0]=[e('<h1 id="v1-1-17-桌面应用集成与-homebrew-升级修复" tabindex="-1">v1.1.17：桌面应用集成与 Homebrew 升级修复 <a class="header-anchor" href="#v1-1-17-桌面应用集成与-homebrew-升级修复" aria-label="Permalink to “v1.1.17：桌面应用集成与 Homebrew 升级修复”">​</a></h1><p><strong>发布日期</strong>：2026年1月13日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新修复了 <strong>Homebrew 自动升级</strong> 功能，并大幅改进了桌面应用与 CLI 的集成体验。</p><hr><h2 id="新功能-桌面应用自动管理-cli" tabindex="-1">新功能：桌面应用自动管理 CLI <a class="header-anchor" href="#新功能-桌面应用自动管理-cli" aria-label="Permalink to “新功能：桌面应用自动管理 CLI”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面应用现在可以自动管理 OpenCode CLI 进程，避免冲突和重复启动。</p><h3 id="对你有什么好处" tabindex="-1">对你有什么好处？ <a class="header-anchor" href="#对你有什么好处" aria-label="Permalink to “对你有什么好处？”">​</a></h3><p>之前的问题：</p><ul><li>macOS 上同时打开桌面应用和 CLI 可能会冲突</li><li>需要手动关闭 CLI 才能启动桌面应用</li></ul><p>现在：</p><ul><li>桌面应用启动时自动关闭旧的 CLI 进程</li><li>CLI 和桌面应用共享认证，不需要重复登录</li><li>Windows 上通过 JobObject 实现生命周期管理</li></ul><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>直接正常使用桌面应用即可，无需额外配置：</p><ol><li>打开桌面应用</li><li>应用会自动处理 CLI 进程</li><li>开始工作</li></ol><hr><h2 id="问题修复-homebrew-自动升级" tabindex="-1">问题修复：Homebrew 自动升级 <a class="header-anchor" href="#问题修复-homebrew-自动升级" aria-label="Permalink to “问题修复：Homebrew 自动升级”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>通过 Homebrew 安装 OpenCode 后，运行 <code>brew upgrade</code> 无法自动更新到最新版本。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>Homebrew 自动升级功能已修复，现在可以通过以下方式更新：</p>',23),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},`# 自动更新所有包（包括 OpenCode）
brew upgrade

# 或者只更新 OpenCode
brew upgrade opencode`)])],-1),e('<hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>通过 Homebrew 安装</td><td>✅ 升级（修复自动升级）</td></tr><tr><td>使用桌面应用</td><td>✅ 升级（改进集成体验）</td></tr><tr><td>只用 TUI，没用 Homebrew</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',4),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),e('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>移除替换包装脚本的 symlinkBinary 函数</li><li>修复 Homebrew 自动升级功能</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>防止对话框打开时触发问题工具的快捷键</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>macOS 启动桌面应用时自动关闭现有的 OpenCode CLI 进程</li><li>在桌面应用中设置 serverPassword</li><li>从桌面应用提供 PTY socket 认证（如果可用）</li><li>将桌面应用和 CLI 绑定到同一个 Windows JobObject</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@zerone0x：修复对话框打开时的问题工具快捷键</li><li>@Brendonovich：多项桌面应用集成改进</li><li>@OpeOginni：优化过滤列表实现</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=l(o,[["render",d]]);export{_ as __pageData,m as default};
